public class LibraryCard {
    private String patronName;
    private int booksCheckedOut;
    private double finesOwed;
    private boolean premium;

    public LibraryCard(String name, boolean isPremium) {
        patronName = name;
        booksCheckedOut = 0;
        finesOwed = 0.0;
        premium = isPremium;
    }

    public void checkOutBook() {
        booksCheckedOut++;
    }

    public void addFine(double amount) {
        finesOwed += amount;
    }

    public String getAccountSummary() {
        String tier;
        if (premium) {
            tier = "Premium Member";
        } else {
            tier = "Standard Member";
        }
        return "Name: " + patronName + "\nBooks Checked Out: " + booksCheckedOut + "\nFines Owed: " + finesOwed + "\nMembership: " + tier;
    }
}

