public class RunningLog {
    private String runnerName;
    private double weeklyGoalMiles;
    private double milesRunThisWeek;
    private int totalRuns;

    public RunningLog(String name, double weeklyGoal) {
        runnerName = name;
        weeklyGoalMiles = weeklyGoal;
        milesRunThisWeek = 0.0;
        totalRuns = 0;
    }

    public RunningLog(String name) {
        runnerName = name;
        weeklyGoalMiles = 0.0;
        milesRunThisWeek = 0.0;
        totalRuns = 0;
    }

    public void logRun(double miles) {
        milesRunThisWeek += miles;
        totalRuns++;
    }

    public boolean onPace() {
        return milesRunThisWeek >= weeklyGoalMiles;
    }

    public String getSummary() {
        return "Runner: " + runnerName + "\nTotal Runs: " + totalRuns + "\nMiles This Week: " + milesRunThisWeek;
    }
}

