public class MovieTicket {
    private String holderName;
    private String movieTitle;
    private boolean premiumSeat;
    private int rewardPoints;

    public MovieTicket(String holder, String movie, boolean isPremium) {
        holderName = holder;
        movieTitle = movie;
        premiumSeat = isPremium;
        rewardPoints = 0;
    }

    public void addPoints(int points) {
        rewardPoints += points;
    }

    public void redeemPoints(int points) {
        if (rewardPoints >= points) {
            rewardPoints -= points;
        }
    }

    public String getTicketInfo() {
        String seatType;
        if (premiumSeat) {
            seatType = "Premium";
        } else {
            seatType = "Standard";
        }
        return "Holder: " + holderName + "\nMovie: " + movieTitle + "\nSeat: " + seatType + "\nReward Points: " + rewardPoints;
    }
}

