public class BookLoan {
    private String title;
    private String patron;
    private int days;
    private int dailyFee;

    public BookLoan(String title, String patron, int days, int dailyFee) {
        this.title = title;
        this.patron = patron;
        this.days = days;
        this.dailyFee = dailyFee;
    }

    public BookLoan(String title, String patron) {
        this.title = title;
        this.patron = patron;
        this.days = 0;
        this.dailyFee = 25;
    }

    public void extendLoan(int extraDays) {
        days += extraDays;
    }

    public int currentFine() {
        if (days <= 14) {
            return 0;
        }
        return (days - 14) * dailyFee;
    }

    public String summary() {
        return title + " borrowed by " + patron + ": " + days + " days, fine = " + currentFine() + "c";
    }
}

