public class CoffeeCard {
    private String name;
    private int tier;
    private int points;
    private boolean autoRenew;

    public CoffeeCard(String name, int tier, int points, boolean autoRenew) {
        this.name = name;
        this.tier = tier;
        this.points = points;
        this.autoRenew = autoRenew;
    }

    public CoffeeCard(String name) {
        this.name = name;
        this.tier = 0;
        this.points = 0;
        this.autoRenew = false;
    }

    public void earnPoints(int amount) {
        points += amount;
    }

    public void upgradeTier() {
        if (tier == 0) {
            tier = 1;
        } else if (tier == 1) {
            tier = 2;
        }
    }

    public String tierLabel() {
        if (tier == 0) {
            return "standard";
        } else if (tier == 1) {
            return "gold";
        }
        return "platinum";
    }

    public String describe() {
        return name + " | " + tierLabel() + " | " + points + " pts | renew=" + autoRenew;
    }
}

